import { Component, OnInit, OnDestroy, inject } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { Router } from '@angular/router';
import { TaskService } from '../../services/task.service';
import { Task, TaskStatus, TaskPriority } from '../../models/task.model';
import { Subject } from 'rxjs';
import { takeUntil } from 'rxjs/operators';

@Component({
  selector: 'app-task-list',
  standalone: true,
  imports: [CommonModule, FormsModule],
  templateUrl: './task-list.component.html',
  styleUrls: ['./task-list.component.scss']
})
export class TaskListComponent implements OnInit, OnDestroy {
  private taskService = inject(TaskService);
  private router = inject(Router);
  private destroy$ = new Subject<void>();

  tasks: Task[] = [];
  filteredTasks: Task[] = [];
  loading = false;
  error = '';
  searchTerm = '';
  selectedFilter: 'all' | 'pending' | 'inProgress' | 'completed' | 'starred' = 'all';
  deleteConfirmId: string | null = null;

  // Status and priority enums for template
  TaskStatus = TaskStatus;
  TaskPriority = TaskPriority;

  ngOnInit(): void {
    this.loadTasks();
  }

  ngOnDestroy(): void {
    this.destroy$.next();
    this.destroy$.complete();
  }

  loadTasks(): void {
    this.loading = true;
    this.error = '';
    this.selectedFilter = 'all'; // Reset filter when loading

    this.taskService.getAllTasks()
      .pipe(takeUntil(this.destroy$))
      .subscribe({
        next: (tasks) => {
          this.tasks = tasks || [];
          this.applyFilters();
          this.loading = false;
        },
        error: (error) => {
          this.error = error.message || 'Failed to load tasks';
          this.tasks = [];
          this.filteredTasks = [];
          this.loading = false;
        }
      });
  }

  applyFilters(): void {
    let filtered = [...this.tasks]; // Create copy to avoid mutations

    // Apply filter
    switch (this.selectedFilter) {
      case 'pending':
        filtered = filtered.filter(t => t.status === 'PENDING' || t.status === TaskStatus.PENDING);
        break;
      case 'inProgress':
        filtered = filtered.filter(t => t.status === 'IN_PROGRESS' || t.status === TaskStatus.IN_PROGRESS);
        break;
      case 'completed':
        filtered = filtered.filter(t => t.status === 'COMPLETED' || t.status === TaskStatus.COMPLETED);
        break;
      case 'starred':
        filtered = filtered.filter(t => t.starred === true);
        break;
      case 'all':
      default:
        // No additional filtering needed for 'all'
        break;
    }

    // Apply search
    if (this.searchTerm && this.searchTerm.trim()) {
      const term = this.searchTerm.toLowerCase();
      filtered = filtered.filter(t =>
        (t.title && t.title.toLowerCase().includes(term)) ||
        (t.description && t.description.toLowerCase().includes(term))
      );
    }

    this.filteredTasks = filtered;
  }

  onFilterChange(): void {
    this.applyFilters();
  }

  onSearchChange(): void {
    this.applyFilters();
  }

  onStatusChange(task: Task, newStatus: string): void {
    this.taskService.updateTaskStatus(task.id, newStatus as TaskStatus)
      .pipe(takeUntil(this.destroy$))
      .subscribe({
        next: () => {
          this.applyFilters();
        },
        error: (error) => {
          this.error = error.message || 'Failed to update task status';
        }
      });
  }

  handleStatusChange(event: Event, task: Task): void {
    const selectElement = event.target as HTMLSelectElement;
    this.onStatusChange(task, selectElement.value);
  }

  toggleStarred(event: Event, task: Task): void {
    event.stopPropagation();
    this.taskService.toggleStarred(task.id)
      .pipe(takeUntil(this.destroy$))
      .subscribe({
        next: () => {
          this.applyFilters();
        },
        error: (error) => {
          this.error = error.message || 'Failed to toggle starred';
        }
      });
  }

  editTask(task: Task): void {
    this.router.navigate(['/tasks', task.id, 'edit']);
  }

  confirmDelete(event: Event, taskId: string): void {
    event.stopPropagation();
    this.deleteConfirmId = taskId;
  }

  cancelDelete(event: Event): void {
    event.stopPropagation();
    this.deleteConfirmId = null;
  }

  deleteTask(event: Event): void {
    event.stopPropagation();
    if (!this.deleteConfirmId) return;

    this.taskService.deleteTask(this.deleteConfirmId)
      .pipe(takeUntil(this.destroy$))
      .subscribe({
        next: () => {
          this.deleteConfirmId = null;
          this.applyFilters();
        },
        error: (error) => {
          this.error = error.message || 'Failed to delete task';
          this.deleteConfirmId = null;
        }
      });
  }

  getPriorityClass(priority: TaskPriority): string {
    switch (priority) {
      case TaskPriority.HIGH:
        return 'priority-high';
      case TaskPriority.MEDIUM:
        return 'priority-medium';
      case TaskPriority.LOW:
        return 'priority-low';
      default:
        return '';
    }
  }

  getStatusClass(status: TaskStatus): string {
    switch (status) {
      case TaskStatus.PENDING:
        return 'status-pending';
      case TaskStatus.IN_PROGRESS:
        return 'status-in-progress';
      case TaskStatus.COMPLETED:
        return 'status-completed';
      case TaskStatus.CANCELLED:
        return 'status-cancelled';
      default:
        return '';
    }
  }

  createNewTask(): void {
    this.router.navigate(['/tasks/create']);
  }
}
<div class="task-list-container">
  <div class="task-list-header">
    <h1>My Tasks</h1>
    <button class="btn btn-primary" (click)="createNewTask()">+ Create Task</button>
  </div>

  <!-- Error Message -->
  @if (error) {
    <div class="alert alert-error">
      <span class="alert-icon">⚠️</span>
      <span>{{ error }}</span>
    </div>
  }

  <!-- Search and Filter Bar -->
  <div class="task-controls">
    <div class="search-box">
      <input
        type="text"
        class="search-input"
        placeholder="Search tasks..."
        [(ngModel)]="searchTerm"
        (change)="onSearchChange()"
      />
      <span class="search-icon">🔍</span>
    </div>

    <div class="filter-buttons">
      <button
        class="filter-btn"
        [class.active]="selectedFilter === 'all'"
        (click)="selectedFilter = 'all'; onFilterChange()"
      >
        All
      </button>
      <button
        class="filter-btn"
        [class.active]="selectedFilter === 'pending'"
        (click)="selectedFilter = 'pending'; onFilterChange()"
      >
        Pending
      </button>
      <button
        class="filter-btn"
        [class.active]="selectedFilter === 'inProgress'"
        (click)="selectedFilter = 'inProgress'; onFilterChange()"
      >
        In Progress
      </button>
      <button
        class="filter-btn"
        [class.active]="selectedFilter === 'completed'"
        (click)="selectedFilter = 'completed'; onFilterChange()"
      >
        Completed
      </button>
      <button
        class="filter-btn"
        [class.active]="selectedFilter === 'starred'"
        (click)="selectedFilter = 'starred'; onFilterChange()"
      >
        ⭐ Starred
      </button>
    </div>
  </div>

  <!-- Loading State -->
  @if (loading) {
    <div class="loading-container">
      <div class="spinner"></div>
      <p>Loading tasks...</p>
    </div>
  }

  <!-- Empty State -->
  @if (!loading && filteredTasks.length === 0) {
    <div class="empty-state">
      <p>📋 No tasks found</p>
      <p class="empty-state-hint">Create a new task to get started</p>
    </div>
  }

  <!-- Tasks List -->
  @if (!loading && filteredTasks.length > 0) {
    <div class="tasks-grid">
      @for (task of filteredTasks; track task.id) {
        <div class="task-card" [class.completed]="task.status === TaskStatus.COMPLETED">
          <div class="task-card-header">
            <div class="task-title-section">
              <select
                [value]="task.status"
                (change)="handleStatusChange($event, task)"
                class="status-select"
                [class]="getStatusClass(task.status)"
              >
                <option value="PENDING">Pending</option>
                <option value="IN_PROGRESS">In Progress</option>
                <option value="COMPLETED">Completed</option>
                <option value="CANCELLED">Cancelled</option>
              </select>
              <h3 class="task-title">{{ task.title }}</h3>
            </div>
            <div class="task-actions">
              <button
                class="action-btn star-btn"
                [class.starred]="task.starred"
                (click)="toggleStarred($event, task)"
                title="Toggle starred"
              >
                {{ task.starred ? '⭐' : '☆' }}
              </button>
              <button
                class="action-btn edit-btn"
                (click)="editTask(task)"
                title="Edit task"
              >
                ✏️
              </button>
              <button
                class="action-btn delete-btn"
                (click)="confirmDelete($event, task.id)"
                title="Delete task"
              >
                🗑️
              </button>
            </div>
          </div>

          <p class="task-description">{{ task.description }}</p>

          <div class="task-meta">
            <div class="meta-item">
              <span class="meta-label">Priority:</span>
              <span [class]="'priority ' + getPriorityClass(task.priority)">
                {{ task.priority }}
              </span>
            </div>

            @if (task.dueDate) {
              <div class="meta-item">
                <span class="meta-label">Due:</span>
                <span>{{ task.dueDate | date: 'MMM d, yyyy' }}</span>
              </div>
            }

            @if (task.category) {
              <div class="meta-item">
                <span class="meta-label">Category:</span>
                <span class="category-badge">{{ task.category }}</span>
              </div>
            }
          </div>

          @if (task.tags && task.tags.length > 0) {
            <div class="task-tags">
              @for (tag of task.tags; track tag) {
                <span class="tag">{{ tag }}</span>
              }
            </div>
          }

          <!-- Delete Confirmation -->
          @if (deleteConfirmId === task.id) {
            <div class="delete-confirmation">
              <p>Are you sure you want to delete this task?</p>
              <div class="confirmation-buttons">
                <button class="btn btn-danger" (click)="deleteTask($event)">Delete</button>
                <button class="btn btn-secondary" (click)="cancelDelete($event)">Cancel</button>
              </div>
            </div>
          }
        </div>
      }
    </div>
  }
</div>
